svg.script:
(function() {
  var root  = document.documentElement;
  var lid   = document.getElementById('wink-lid');
  var PIVOT_Y = 205;
  var winking = false;

  function setLidScale(s) {
    var t = 'translate(0 ' + PIVOT_Y + ') scale(1 ' + s + ') translate(0 ' + (-PIVOT_Y) + ')';
    lid.setAttribute('transform', t);
  }

  setLidScale(0); // start hidden

  function ease(x) { return x < 0.5 ? 2*x*x : 1 - Math.pow(-2*x+2,2)/2; }

  function doWink() {
    if (winking) return;
    winking = true;
    var t0 = null;
    var DUR = 700;

    function step(ts) {
      if (!t0) t0 = ts;
      var p = Math.min((ts - t0) / DUR, 1);
      var s;
      if      (p < 0.28) s = ease(p / 0.28);
      else if (p < 0.66) s = 1;
      else               s = 1 - ease((p - 0.66) / 0.34);
      setLidScale(Math.max(0, Math.min(1, s)));
      if (p < 1) requestAnimationFrame(step);
      else { setLidScale(0); winking = false; }
    }
    requestAnimationFrame(step);
  }

  root.addEventListener('mouseenter', doWink);
})();
